import Foundation

class HTTPClient {
    private let session: URLSession
    
    init() {
        let configuration = URLSessionConfiguration.default
        configuration.httpAdditionalHeaders = ["Content-Type": "application/json"]
        
        // Allow insecure connections for testing purposes
        if #available(iOS 11.0, *) {
            configuration.waitsForConnectivity = true
        }
        session = URLSession(configuration: configuration)
    }
    
    func request(urlString: String, method: String = "GET", body: Data? = nil, completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = URL(string: urlString) else {
            completion(.failure(NSError(domain: "InvalidURL", code: -1, userInfo: nil)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        if let bodyData = body {
            request.httpBody = bodyData
        }
        
        // Disable SSL pinning for testing purposes
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NSError(domain: "HTTPError", code: -1, userInfo: nil)))
                return
            }
            
            if let data = data {
                completion(.success(data))
            } else {
                completion(.failure(NSError(domain: "NoData", code: -1, userInfo: nil)))
            }
        }
        
        task.resume()
    }
}

